import{_ as e,o as t,c as a,b as r}from"./app.83d10e71.js";const _='{"title":"Experiments","description":"","frontmatter":{"title":"Experiments","subtitle":"Standalone apps and external music resources","date":"2021-03-02T00:00:00.000Z","cover":"experiments.png"},"headers":[],"relativePath":"apps/experiment/index.md"}',o={},n=r('<p>Here&#39;s our collection of various web music experiments built by us or other creators.</p><p><a href="./touchme/">TouchMe Experience</a> is an online MIDI synth and visualizer built in collaboration with <a href="https://playtronica.com" class="external-link" target="_blank" rel="noopener noreferrer">Playtronica</a> for the <strong>TouchMe</strong> controller.</p><p><a href="./ambience/">Ambient drone box</a> is an experiment where simplex noise meets generative music.</p><p>Here&#39;s the universal <a href="./fretboard/">Fretboard calculator</a> that may help you build your own custom fretted string instrument with any given dimestions.</p><p>We haven&#39;t ported the fabulous <a href="./paper/">MIDI Paper</a> visualizer yet, but you may play with it standalone. The <a href="./lab/">Sound Laboratory</a> is another powerful standalone tool to explore basic sound synthesis and effect chains. Some even more old experiments are at <a href="./dev/">Dev</a>.</p><p>The <a href="./spectrum/">Spectrum analyzer</a> is a basic sound analysis visualization to build upon..</p><p>And there&#39;s a ever growing collection of <a href="./other/">Other music web-apps</a> found on the internet.</p>',7),s=[n];function i(p,l,c,u,h,d){return t(),a("div",null,s)}var f=e(o,[["render",i]]);export{_ as __pageData,f as default};
